#include <iostream>

int compute(int a, int b, int c) {
    int sum = a + b;
    std::cerr << "[watch] sum=" << sum << "\n";

    int scaled = sum * c;
    std::cerr << "[watch] scaled=" << scaled << "\n";

    int result = scaled - b;
    std::cerr << "[watch] result=" << result << "\n";

    return result;
}

int main() {
    int a, b, c;
    std::cin >> a >> b >> c;
    std::cout << compute(a, b, c) << "\n";
    return 0;
}

