#include <iostream>

int watched_total(int a, int b, int c) {
    int t1 = a;
    std::cerr << "[watch] t1=" << t1 << "\n";
    int t2 = t1 + b;
    std::cerr << "[watch] t2=" << t2 << "\n";
    int t3 = t2 + c;
    std::cerr << "[watch] t3=" << t3 << "\n";
    return t3;
}

int main() {
    int a, b, c;
    std::cin >> a >> b >> c;
    std::cout << watched_total(a, b, c) << "\n";
    return 0;
}
